package com.example.api.util;

public final class LogSanitizer {

    private LogSanitizer() {
    }

    /**
     * Sanitizes user-supplied input before including it in log messages.
     * Prevents log injection by removing newlines, carriage returns,
     * and other control characters that could forge log entries.
     */
    public static String sanitize(String input) {
        if (input == null) {
            return "null";
        }
        return input
                .replace("\r", "")
                .replace("\n", "")
                .replace("\t", " ")
                .replaceAll("[\\p{Cntrl}]", "")
                .trim();
    }

    /**
     * Masks sensitive data for logging purposes (e.g., email, IDs).
     * Shows only first 3 and last 2 characters for strings longer than 7 chars.
     */
    public static String mask(String sensitive) {
        if (sensitive == null) {
            return "null";
        }
        if (sensitive.length() <= 7) {
            return "***";
        }
        return sensitive.substring(0, 3) + "***" + sensitive.substring(sensitive.length() - 2);
    }
}

