package com.example.api.util;

public enum SecurityEvent {
    AUTHENTICATION_SUCCESS,
    AUTHENTICATION_FAILURE,
    AUTHORIZATION_FAILURE,
    INPUT_VALIDATION_FAILURE,
    RESOURCE_ACCESS,
    RESOURCE_CREATED,
    RESOURCE_UPDATED,
    RESOURCE_DELETED,
    RESOURCE_NOT_FOUND,
    RATE_LIMIT_EXCEEDED,
    SUSPICIOUS_ACTIVITY,
    APPLICATION_ERROR
}

