package com.example.api.util;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;

import java.time.Instant;

public final class SecurityLogger {

    private static final Logger securityLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    private SecurityLogger() {
    }

    public static void log(SecurityEvent event, String userId, String action, String detail, String sourceIp) {
        String safeUserId = LogSanitizer.sanitize(userId);
        String safeAction = LogSanitizer.sanitize(action);
        String safeDetail = LogSanitizer.sanitize(detail);
        String safeSourceIp = LogSanitizer.sanitize(sourceIp);

        MDC.put("securityEvent", event.name());
        MDC.put("userId", safeUserId);
        MDC.put("sourceIp", safeSourceIp);
        MDC.put("eventTimestamp", Instant.now().toString());

        try {
            switch (event) {
                case AUTHENTICATION_FAILURE:
                case AUTHORIZATION_FAILURE:
                case SUSPICIOUS_ACTIVITY:
                case RATE_LIMIT_EXCEEDED:
                    securityLog.warn("event={} user={} action={} detail={} sourceIp={}",
                            event, safeUserId, safeAction, safeDetail, safeSourceIp);
                    break;
                case APPLICATION_ERROR:
                    securityLog.error("event={} user={} action={} detail={} sourceIp={}",
                            event, safeUserId, safeAction, safeDetail, safeSourceIp);
                    break;
                default:
                    securityLog.info("event={} user={} action={} detail={} sourceIp={}",
                            event, safeUserId, safeAction, safeDetail, safeSourceIp);
                    break;
            }
        } finally {
            MDC.remove("securityEvent");
            MDC.remove("userId");
            MDC.remove("sourceIp");
            MDC.remove("eventTimestamp");
        }
    }
}

