package com.example.api.filter;

import com.example.api.util.LogSanitizer;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.core.Ordered;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.UUID;

@Component
@Order(Ordered.HIGHEST_PRECEDENCE)
public class RequestLoggingFilter extends OncePerRequestFilter {

    private static final Logger log = LoggerFactory.getLogger(RequestLoggingFilter.class);

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {
        String correlationId = UUID.randomUUID().toString();
        long startTime = System.currentTimeMillis();

        MDC.put("correlationId", correlationId);
        MDC.put("clientIp", getClientIp(request));
        MDC.put("method", request.getMethod());
        MDC.put("uri", LogSanitizer.sanitize(request.getRequestURI()));

        response.setHeader("X-Correlation-Id", correlationId);

        try {
            log.info("Incoming request: method={} uri={} clientIp={} userAgent={}",
                    request.getMethod(),
                    LogSanitizer.sanitize(request.getRequestURI()),
                    getClientIp(request),
                    LogSanitizer.sanitize(request.getHeader("User-Agent")));

            filterChain.doFilter(request, response);

            long duration = System.currentTimeMillis() - startTime;
            log.info("Completed request: method={} uri={} status={} durationMs={}",
                    request.getMethod(),
                    LogSanitizer.sanitize(request.getRequestURI()),
                    response.getStatus(),
                    duration);
        } finally {
            MDC.clear();
        }
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return LogSanitizer.sanitize(xForwardedFor.split(",")[0].trim());
        }
        return request.getRemoteAddr();
    }
}

