package com.example.api.service;

import com.example.api.exception.ItemNotFoundException;
import com.example.api.model.Item;
import com.example.api.util.LogSanitizer;
import com.example.api.util.SecurityEvent;
import com.example.api.util.SecurityLogger;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class ItemService {

    private static final Logger log = LoggerFactory.getLogger(ItemService.class);

    private final Map<Long, Item> itemStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(1);

    public ItemService() {
        // Seed some initial data
        createItem(new Item(null, "Sample Item 1", "First sample item"), "system", "127.0.0.1");
        createItem(new Item(null, "Sample Item 2", "Second sample item"), "system", "127.0.0.1");
        log.info("ItemService initialized with seed data, itemCount={}", itemStore.size());
    }

    public List<Item> getAllItems(String userId, String sourceIp) {
        log.debug("Retrieving all items, userId={}", LogSanitizer.sanitize(userId));

        List<Item> items = new ArrayList<>(itemStore.values());

        SecurityLogger.log(SecurityEvent.RESOURCE_ACCESS, userId,
                "GET_ALL_ITEMS", "Retrieved " + items.size() + " items", sourceIp);

        log.info("Successfully retrieved all items, count={} userId={}",
                items.size(), LogSanitizer.sanitize(userId));

        return Collections.unmodifiableList(items);
    }

    public Item getItemById(Long id, String userId, String sourceIp) {
        log.debug("Retrieving item, itemId={} userId={}", id, LogSanitizer.sanitize(userId));

        Item item = itemStore.get(id);
        if (item == null) {
            SecurityLogger.log(SecurityEvent.RESOURCE_NOT_FOUND, userId,
                    "GET_ITEM", "Item not found with id=" + id, sourceIp);
            log.warn("Item not found, itemId={} userId={}", id, LogSanitizer.sanitize(userId));
            throw new ItemNotFoundException(id);
        }

        SecurityLogger.log(SecurityEvent.RESOURCE_ACCESS, userId,
                "GET_ITEM", "Retrieved item id=" + id, sourceIp);

        log.info("Successfully retrieved item, itemId={} userId={}", id, LogSanitizer.sanitize(userId));
        return item;
    }

    public Item createItem(Item item, String userId, String sourceIp) {
        Long newId = idGenerator.getAndIncrement();
        item.setId(newId);
        itemStore.put(newId, item);

        SecurityLogger.log(SecurityEvent.RESOURCE_CREATED, userId,
                "CREATE_ITEM", "Created item id=" + newId + " name=" + LogSanitizer.sanitize(item.getName()),
                sourceIp);

        log.info("Successfully created item, itemId={} userId={}", newId, LogSanitizer.sanitize(userId));
        return item;
    }

    public Item updateItem(Long id, Item updatedItem, String userId, String sourceIp) {
        log.debug("Updating item, itemId={} userId={}", id, LogSanitizer.sanitize(userId));

        Item existingItem = itemStore.get(id);
        if (existingItem == null) {
            SecurityLogger.log(SecurityEvent.RESOURCE_NOT_FOUND, userId,
                    "UPDATE_ITEM", "Item not found with id=" + id, sourceIp);
            log.warn("Update failed - item not found, itemId={} userId={}", id, LogSanitizer.sanitize(userId));
            throw new ItemNotFoundException(id);
        }

        updatedItem.setId(id);
        itemStore.put(id, updatedItem);

        SecurityLogger.log(SecurityEvent.RESOURCE_UPDATED, userId,
                "UPDATE_ITEM", "Updated item id=" + id, sourceIp);

        log.info("Successfully updated item, itemId={} userId={}", id, LogSanitizer.sanitize(userId));
        return updatedItem;
    }

    public void deleteItem(Long id, String userId, String sourceIp) {
        log.debug("Deleting item, itemId={} userId={}", id, LogSanitizer.sanitize(userId));

        Item removed = itemStore.remove(id);
        if (removed == null) {
            SecurityLogger.log(SecurityEvent.RESOURCE_NOT_FOUND, userId,
                    "DELETE_ITEM", "Item not found with id=" + id, sourceIp);
            log.warn("Delete failed - item not found, itemId={} userId={}", id, LogSanitizer.sanitize(userId));
            throw new ItemNotFoundException(id);
        }

        SecurityLogger.log(SecurityEvent.RESOURCE_DELETED, userId,
                "DELETE_ITEM", "Deleted item id=" + id, sourceIp);

        log.info("Successfully deleted item, itemId={} userId={}", id, LogSanitizer.sanitize(userId));
    }
}

