package com.example.api.controller;

import com.example.api.model.Item;
import com.example.api.service.ItemService;
import com.example.api.util.LogSanitizer;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.security.Principal;
import java.util.List;

@RestController
@RequestMapping("/api/v1/items")
public class ItemController {

    private static final Logger log = LoggerFactory.getLogger(ItemController.class);

    private final ItemService itemService;

    public ItemController(ItemService itemService) {
        this.itemService = itemService;
    }

    @GetMapping
    public ResponseEntity<List<Item>> getAllItems(Principal principal, HttpServletRequest request) {
        String userId = getUserId(principal);
        String clientIp = getClientIp(request);

        log.info("GET /api/v1/items requested by userId={}", LogSanitizer.sanitize(userId));

        List<Item> items = itemService.getAllItems(userId, clientIp);
        return ResponseEntity.ok(items);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Item> getItemById(@PathVariable Long id, Principal principal,
                                             HttpServletRequest request) {
        String userId = getUserId(principal);
        String clientIp = getClientIp(request);

        log.info("GET /api/v1/items/{} requested by userId={}", id, LogSanitizer.sanitize(userId));

        Item item = itemService.getItemById(id, userId, clientIp);
        return ResponseEntity.ok(item);
    }

    @PostMapping
    public ResponseEntity<Item> createItem(@Valid @RequestBody Item item, Principal principal,
                                            HttpServletRequest request) {
        String userId = getUserId(principal);
        String clientIp = getClientIp(request);

        log.info("POST /api/v1/items requested by userId={} itemName={}",
                LogSanitizer.sanitize(userId), LogSanitizer.sanitize(item.getName()));

        Item created = itemService.createItem(item, userId, clientIp);
        return ResponseEntity.status(HttpStatus.CREATED).body(created);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Item> updateItem(@PathVariable Long id, @Valid @RequestBody Item item,
                                            Principal principal, HttpServletRequest request) {
        String userId = getUserId(principal);
        String clientIp = getClientIp(request);

        log.info("PUT /api/v1/items/{} requested by userId={}", id, LogSanitizer.sanitize(userId));

        Item updated = itemService.updateItem(id, item, userId, clientIp);
        return ResponseEntity.ok(updated);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteItem(@PathVariable Long id, Principal principal,
                                            HttpServletRequest request) {
        String userId = getUserId(principal);
        String clientIp = getClientIp(request);

        log.info("DELETE /api/v1/items/{} requested by userId={}", id, LogSanitizer.sanitize(userId));

        itemService.deleteItem(id, userId, clientIp);
        return ResponseEntity.noContent().build();
    }

    private String getUserId(Principal principal) {
        return principal != null ? principal.getName() : "anonymous";
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return LogSanitizer.sanitize(xForwardedFor.split(",")[0].trim());
        }
        return request.getRemoteAddr();
    }
}

