package com.example.api.exception;

import com.example.api.model.ApiErrorResponse;
import com.example.api.util.LogSanitizer;
import com.example.api.util.SecurityEvent;
import com.example.api.util.SecurityLogger;
import jakarta.servlet.http.HttpServletRequest;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;
import org.springframework.web.method.annotation.MethodArgumentTypeMismatchException;

import java.util.List;
import java.util.stream.Collectors;

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(ItemNotFoundException.class)
    public ResponseEntity<ApiErrorResponse> handleItemNotFound(ItemNotFoundException ex,
                                                                 HttpServletRequest request) {
        log.warn("Item not found: itemId={} uri={}", ex.getItemId(),
                LogSanitizer.sanitize(request.getRequestURI()));

        ApiErrorResponse error = new ApiErrorResponse(
                HttpStatus.NOT_FOUND.value(),
                "Not Found",
                "The requested item was not found",
                MDC.get("correlationId"),
                null
        );
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ApiErrorResponse> handleValidationErrors(MethodArgumentNotValidException ex,
                                                                     HttpServletRequest request) {
        List<String> details = ex.getBindingResult().getFieldErrors().stream()
                .map(fieldError -> fieldError.getField() + ": " + fieldError.getDefaultMessage())
                .collect(Collectors.toList());

        String clientIp = getClientIp(request);

        SecurityLogger.log(SecurityEvent.INPUT_VALIDATION_FAILURE, "unknown",
                "VALIDATION", "Validation failed on " + LogSanitizer.sanitize(request.getRequestURI()) +
                        " fields=" + details.size(), clientIp);

        log.warn("Validation failed: uri={} errors={}", LogSanitizer.sanitize(request.getRequestURI()), details);

        ApiErrorResponse error = new ApiErrorResponse(
                HttpStatus.BAD_REQUEST.value(),
                "Validation Error",
                "Request validation failed",
                MDC.get("correlationId"),
                details
        );
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }

    @ExceptionHandler(MethodArgumentTypeMismatchException.class)
    public ResponseEntity<ApiErrorResponse> handleTypeMismatch(MethodArgumentTypeMismatchException ex,
                                                                 HttpServletRequest request) {
        String clientIp = getClientIp(request);

        SecurityLogger.log(SecurityEvent.INPUT_VALIDATION_FAILURE, "unknown",
                "TYPE_MISMATCH", "Invalid parameter type on " + LogSanitizer.sanitize(request.getRequestURI()),
                clientIp);

        log.warn("Type mismatch: uri={} parameter={}", LogSanitizer.sanitize(request.getRequestURI()),
                LogSanitizer.sanitize(ex.getName()));

        ApiErrorResponse error = new ApiErrorResponse(
                HttpStatus.BAD_REQUEST.value(),
                "Bad Request",
                "Invalid parameter type",
                MDC.get("correlationId"),
                null
        );
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiErrorResponse> handleGenericException(Exception ex, HttpServletRequest request) {
        String clientIp = getClientIp(request);

        SecurityLogger.log(SecurityEvent.APPLICATION_ERROR, "unknown",
                "UNHANDLED_ERROR", "Unhandled exception on " + LogSanitizer.sanitize(request.getRequestURI()),
                clientIp);

        // Log the full stack trace for internal debugging but don't expose to client
        log.error("Unhandled exception: uri={} message={}", LogSanitizer.sanitize(request.getRequestURI()),
                ex.getMessage(), ex);

        ApiErrorResponse error = new ApiErrorResponse(
                HttpStatus.INTERNAL_SERVER_ERROR.value(),
                "Internal Server Error",
                "An unexpected error occurred. Please reference correlationId for support.",
                MDC.get("correlationId"),
                null
        );
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error);
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return LogSanitizer.sanitize(xForwardedFor.split(",")[0].trim());
        }
        return request.getRemoteAddr();
    }
}

