package com.example.api.config;

import com.example.api.util.LogSanitizer;
import com.example.api.util.SecurityEvent;
import com.example.api.util.SecurityLogger;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.context.event.EventListener;
import org.springframework.security.authentication.event.AbstractAuthenticationFailureEvent;
import org.springframework.security.authentication.event.AuthenticationSuccessEvent;
import org.springframework.stereotype.Component;

@Component
public class AuthenticationEventListener {

    private static final Logger log = LoggerFactory.getLogger(AuthenticationEventListener.class);

    @EventListener
    public void onAuthenticationSuccess(AuthenticationSuccessEvent event) {
        String username = event.getAuthentication().getName();

        SecurityLogger.log(SecurityEvent.AUTHENTICATION_SUCCESS, username,
                "LOGIN", "User authenticated successfully", "N/A");

        log.info("Authentication success: userId={}", LogSanitizer.sanitize(username));
    }

    @EventListener
    public void onAuthenticationFailure(AbstractAuthenticationFailureEvent event) {
        String username = event.getAuthentication().getName();
        String failureReason = event.getException().getMessage();

        SecurityLogger.log(SecurityEvent.AUTHENTICATION_FAILURE, username,
                "LOGIN_FAILED", "Authentication failed: " + LogSanitizer.sanitize(failureReason), "N/A");

        log.warn("Authentication failure: userId={} reason={}",
                LogSanitizer.sanitize(username), LogSanitizer.sanitize(failureReason));
    }
}

